<span class="line" data-v-ca4cf977><span style="--shiki-light:#998418;--shiki-dark:#B8A965;" data-v-ca4cf977>  scrollbar-gutter</span><span style="--shiki-light:#999999;--shiki-dark:#666666;" data-v-ca4cf977>:</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;" data-v-ca4cf977> stable</span><span style="--shiki-light:#999999;--shiki-dark:#666666;" data-v-ca4cf977>;</span></span>
